import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Home, Utensils, Calendar, Image as ImageIcon, Star, MessageCircle, Menu as MenuIcon, X, MapPin, Phone, ChevronRight, ShoppingBag } from 'lucide-react';
import HomePage from './pages/HomePage';
import MenuPage from './pages/MenuPage';
import BookPage from './pages/BookPage';
import GalleryPage from './pages/GalleryPage';
import ReviewsPage from './pages/ReviewsPage';
import ContactPage from './pages/ContactPage';
import Loader from './components/Loader';
import { COLORS, CONTACT_NUMBER } from './constants';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 2500);
    return () => clearTimeout(timer);
  }, []);

  if (loading) return <Loader />;

  return (
    <Router>
      <div className="min-h-screen bg-[#121212] text-[#F8F9FA] pb-24">
        {/* Top Navbar */}
        <nav className="fixed top-0 w-full z-50 glass border-b border-white/5 px-6 py-4 flex items-center justify-between">
          <Link to="/" className="text-xl font-bold tracking-tighter flex items-center gap-2">
            <div className="w-8 h-8 rounded-full bg-[#00C853] flex items-center justify-center text-black font-black">0°</div>
            <span>ZERO DEGREES</span>
          </Link>
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="p-2 hover:bg-white/5 rounded-full transition-colors"
          >
            <MenuIcon size={24} />
          </button>
        </nav>

        {/* Sidebar Drawer */}
        <div className={`fixed inset-0 z-[60] transition-opacity duration-300 ${isSidebarOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)} />
          <div className={`absolute top-0 right-0 w-80 h-full bg-[#1A1A1A] transition-transform duration-500 transform ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'} p-8 flex flex-col`}>
            <button 
              onClick={() => setIsSidebarOpen(false)}
              className="self-end p-2 mb-8 bg-white/5 rounded-full"
            >
              <X size={24} />
            </button>
            <div className="flex flex-col gap-6 text-2xl font-medium">
              <NavLink to="/" onClick={() => setIsSidebarOpen(false)}>Home</NavLink>
              <NavLink to="/menu" onClick={() => setIsSidebarOpen(false)}>Menu</NavLink>
              <NavLink to="/book" onClick={() => setIsSidebarOpen(false)}>Book a Table</NavLink>
              <NavLink to="/gallery" onClick={() => setIsSidebarOpen(false)}>Gallery</NavLink>
              <NavLink to="/reviews" onClick={() => setIsSidebarOpen(false)}>Reviews</NavLink>
              <NavLink to="/contact" onClick={() => setIsSidebarOpen(false)}>Contact</NavLink>
            </div>
            <div className="mt-auto pt-8 border-t border-white/5">
              <p className="text-sm text-gray-500 mb-2">Located at Kota</p>
              <a href={`tel:${CONTACT_NUMBER}`} className="flex items-center gap-2 text-[#00C853]">
                <Phone size={16} />
                <span>+91 {CONTACT_NUMBER}</span>
              </a>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <main className="pt-20 px-4 md:px-0">
          <Routes>
            <Route path="/" element={<HomePage />} />
            <Route path="/menu" element={<MenuPage />} />
            <Route path="/book" element={<BookPage />} />
            <Route path="/gallery" element={<GalleryPage />} />
            <Route path="/reviews" element={<ReviewsPage />} />
            <Route path="/contact" element={<ContactPage />} />
          </Routes>
        </main>

        {/* Floating WhatsApp Button */}
        <a 
          href={`https://wa.me/${CONTACT_NUMBER}`}
          target="_blank"
          rel="noopener noreferrer"
          className="fixed bottom-28 right-6 z-40 bg-[#25D366] text-white p-4 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all"
        >
          <MessageCircle size={28} />
        </a>

        {/* Bottom Navigation */}
        <div className="fixed bottom-0 w-full z-50 glass border-t border-white/5 px-6 py-4 flex items-center justify-around">
          <BottomNavItem to="/" icon={<Home size={22} />} label="Home" />
          <BottomNavItem to="/menu" icon={<Utensils size={22} />} label="Menu" />
          <BottomNavItem to="/book" icon={<Calendar size={22} />} label="Book" />
          <BottomNavItem to="/contact" icon={<MapPin size={22} />} label="Locate" />
        </div>
      </div>
    </Router>
  );
};

const NavLink: React.FC<{ to: string, children: React.ReactNode, onClick: () => void }> = ({ to, children, onClick }) => (
  <Link to={to} onClick={onClick} className="hover:text-[#00C853] transition-colors">{children}</Link>
);

const BottomNavItem: React.FC<{ to: string, icon: React.ReactNode, label: string }> = ({ to, icon, label }) => {
  const location = useLocation();
  const isActive = location.pathname === to;
  return (
    <Link to={to} className={`flex flex-col items-center gap-1 transition-all ${isActive ? 'text-[#00C853]' : 'text-gray-400'}`}>
      {icon}
      <span className="text-[10px] font-medium uppercase tracking-wider">{label}</span>
    </Link>
  );
};

export default App;

import React, { useState, useEffect } from 'react';

const Loader: React.FC = () => {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => (prev < 100 ? prev + 1 : 100));
    }, 15);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="fixed inset-0 bg-[#121212] z-[100] flex flex-col items-center justify-center p-12">
      <div className="relative overflow-hidden">
        <h1 className="text-6xl md:text-8xl font-black tracking-tighter leading-none text-white/10 italic">
          ZERO DEGREES
        </h1>
        <h1 
          className="absolute top-0 left-0 text-6xl md:text-8xl font-black tracking-tighter leading-none text-[#00C853] italic transition-all duration-300"
          style={{ clipPath: `inset(0 ${100 - progress}% 0 0)` }}
        >
          ZERO DEGREES
        </h1>
      </div>
      <div className="mt-8 flex items-end gap-2">
        <span className="text-4xl font-light text-white italic">{progress}%</span>
        <span className="text-sm uppercase tracking-[0.4em] text-gray-500 mb-1">Loading Perfection</span>
      </div>
      <div className="mt-12 w-full max-w-xs h-[1px] bg-white/10 overflow-hidden">
        <div 
          className="h-full bg-[#00C853] transition-all duration-300" 
          style={{ width: `${progress}%` }}
        />
      </div>
    </div>
  );
};

export default Loader;

import React, { useState } from 'react';
import { Search, Info, Plus, ShoppingBag, X, ChefHat, Timer, Flame } from 'lucide-react';
import { MENU_ITEMS } from '../constants';
import { MenuItem } from '../types';

const MenuPage: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [selectedItem, setSelectedItem] = useState<MenuItem | null>(null);

  const categories = ['All', ...Array.from(new Set(MENU_ITEMS.map(i => i.category)))];

  const filteredItems = MENU_ITEMS.filter(item => {
    const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || item.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-8 pb-12">
      <div className="px-2">
        <h1 className="text-4xl font-bold tracking-tighter mb-2">Our Menu</h1>
        <p className="text-gray-500 italic">Freshly crafted vegetarian wonders</p>
      </div>

      {/* Search and Filter */}
      <div className="sticky top-20 z-40 space-y-4 px-2 bg-[#121212]/80 backdrop-blur-lg pb-4">
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={20} />
          <input 
            type="text"
            placeholder="Search for your favorite burger..."
            className="w-full bg-[#1A1A1A] border border-white/5 rounded-2xl h-14 pl-12 pr-4 focus:ring-2 focus:ring-[#00C853] outline-none transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 overflow-x-auto no-scrollbar py-2">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`px-6 py-2 rounded-full whitespace-nowrap text-sm font-medium transition-all ${
                selectedCategory === cat 
                ? 'bg-[#00C853] text-black shadow-[0_0_20px_rgba(0,200,83,0.3)]' 
                : 'bg-[#1A1A1A] border border-white/5 text-gray-400'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Menu Grid */}
      <div className="grid gap-6 px-2">
        {filteredItems.map(item => (
          <div 
            key={item.id} 
            onClick={() => setSelectedItem(item)}
            className="bg-[#1A1A1A] rounded-3xl border border-white/5 p-4 flex gap-4 active:scale-[0.98] transition-all cursor-pointer shadow-lg"
          >
            <div className="w-24 h-24 rounded-2xl overflow-hidden flex-shrink-0 relative">
              <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
              {item.isSpicy && (
                <div className="absolute bottom-1 right-1 bg-red-500 p-1 rounded-full text-white">
                  <Flame size={12} fill="currentColor" />
                </div>
              )}
            </div>
            <div className="flex-grow flex flex-col justify-between py-1">
              <div>
                <h3 className="font-bold text-lg leading-tight mb-1">{item.name}</h3>
                <p className="text-xs text-gray-500 line-clamp-2 font-light">{item.description}</p>
              </div>
              <div className="flex items-center justify-between">
                <span className="font-bold text-[#00C853] text-xl">₹{item.price}</span>
                <div className="bg-white/5 rounded-lg px-2 py-1 flex items-center gap-1 text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                  <Timer size={10} /> {item.prepTime}
                </div>
              </div>
            </div>
            <button className="bg-[#00C853] self-center p-3 rounded-2xl text-black shadow-lg">
              <Plus size={20} />
            </button>
          </div>
        ))}
      </div>

      {/* Item Detail Drawer */}
      {selectedItem && (
        <div className="fixed inset-0 z-[70] flex items-end">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={() => setSelectedItem(null)} />
          <div className="relative w-full bg-[#1A1A1A] rounded-t-[3rem] p-8 animate-slide-up shadow-2xl overflow-y-auto max-h-[90vh]">
            <button 
              onClick={() => setSelectedItem(null)}
              className="absolute top-6 right-6 p-2 bg-white/5 rounded-full"
            >
              <X size={24} />
            </button>

            <div className="mb-8">
              <div className="w-full h-64 rounded-3xl overflow-hidden mb-6">
                <img src={selectedItem.image} alt={selectedItem.name} className="w-full h-full object-cover" />
              </div>
              <div className="flex items-center gap-3 mb-4">
                <span className="bg-[#00C853]/10 text-[#00C853] px-4 py-1 rounded-full text-xs font-bold tracking-widest uppercase">
                  {selectedItem.category}
                </span>
                {selectedItem.isSpicy && (
                  <span className="bg-red-500/10 text-red-500 px-4 py-1 rounded-full text-xs font-bold tracking-widest uppercase flex items-center gap-1">
                    <Flame size={12} /> Extra Spicy
                  </span>
                )}
              </div>
              <h2 className="text-4xl font-black italic tracking-tighter mb-4">{selectedItem.name}</h2>
              <p className="text-gray-400 text-lg font-light leading-relaxed mb-8">
                {selectedItem.description}
              </p>

              <div className="grid grid-cols-2 gap-4 mb-8">
                <div className="bg-white/5 p-4 rounded-2xl flex items-center gap-4 border border-white/5">
                  <div className="w-10 h-10 rounded-xl bg-[#00C853]/10 flex items-center justify-center text-[#00C853]">
                    <Timer size={20} />
                  </div>
                  <div>
                    <p className="text-[10px] text-gray-500 uppercase tracking-widest">Prep Time</p>
                    <p className="font-bold">{selectedItem.prepTime}</p>
                  </div>
                </div>
                <div className="bg-white/5 p-4 rounded-2xl flex items-center gap-4 border border-white/5">
                  <div className="w-10 h-10 rounded-xl bg-[#FFD700]/10 flex items-center justify-center text-[#FFD700]">
                    <ChefHat size={20} />
                  </div>
                  <div>
                    <p className="text-[10px] text-gray-500 uppercase tracking-widest">Pure Veg</p>
                    <p className="font-bold">Organic</p>
                  </div>
                </div>
              </div>

              <div className="flex items-center justify-between pt-6 border-t border-white/5">
                <div>
                  <p className="text-[10px] text-gray-500 uppercase tracking-widest mb-1">Price</p>
                  <p className="text-4xl font-black text-[#00C853]">₹{selectedItem.price}</p>
                </div>
                <button className="bg-[#00C853] text-black h-16 px-10 rounded-2xl font-black text-lg flex items-center gap-3 active:scale-95 transition-all shadow-xl">
                  ADD TO ORDER <ShoppingBag size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes slide-up {
          from { transform: translateY(100%); }
          to { transform: translateY(0); }
        }
        .animate-slide-up {
          animation: slide-up 0.4s cubic-bezier(0.16, 1, 0.3, 1);
        }
      `}</style>
    </div>
  );
};

export default MenuPage;

import React, { useState } from 'react';
import { Calendar, Users, Clock, MapPin, Send, CheckCircle2 } from 'lucide-react';
import { CONTACT_NUMBER } from '../constants';
import { Booking } from '../types';

const BookPage: React.FC = () => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<Booking>({
    name: '',
    contact: '',
    date: new Date().toISOString().split('T')[0],
    time: '18:00',
    guests: 2,
    location: 'indoor',
    notes: ''
  });

  const handleBook = () => {
    const message = `Hello ZERO DEGREES KOTA! I would like to book a table:%0A%0AName: ${formData.name}%0AContact: ${formData.contact}%0ADate: ${formData.date}%0ATime: ${formData.time}%0AGuests: ${formData.guests}%0ALocation: ${formData.location}%0ANotes: ${formData.notes}%0A%0APlease confirm my booking.`;
    window.open(`https://wa.me/${CONTACT_NUMBER}?text=${message}`, '_blank');
    setStep(2);
  };

  if (step === 2) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[70vh] text-center px-6 animate-fade-in">
        <div className="w-24 h-24 bg-[#00C853]/20 text-[#00C853] rounded-full flex items-center justify-center mb-8">
          <CheckCircle2 size={48} />
        </div>
        <h1 className="text-4xl font-black italic tracking-tighter mb-4">REQUEST SENT!</h1>
        <p className="text-gray-400 text-lg font-light leading-relaxed mb-12">
          We've sent your details to our team via WhatsApp. Please check your chat for confirmation.
        </p>
        <button 
          onClick={() => setStep(1)}
          className="w-full h-16 bg-white/5 border border-white/10 rounded-2xl font-bold hover:bg-white/10 transition-all"
        >
          Book Another Table
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-8 pb-12 px-2">
      <div>
        <h1 className="text-4xl font-black italic tracking-tighter mb-2 uppercase">RESERVE A SPOT</h1>
        <p className="text-gray-500">Fine dining at the heart of Kota</p>
      </div>

      <div className="bg-[#1A1A1A] rounded-[2.5rem] border border-white/5 p-8 shadow-2xl space-y-6">
        <div className="space-y-2">
          <label className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Your Name</label>
          <input 
            type="text" 
            placeholder="John Doe"
            className="w-full bg-black/30 border border-white/5 rounded-xl h-14 px-4 focus:ring-2 focus:ring-[#00C853] outline-none transition-all"
            value={formData.name}
            onChange={e => setFormData({...formData, name: e.target.value})}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Contact Number</label>
          <input 
            type="tel" 
            placeholder="+91 XXXXX XXXXX"
            className="w-full bg-black/30 border border-white/5 rounded-xl h-14 px-4 focus:ring-2 focus:ring-[#00C853] outline-none transition-all"
            value={formData.contact}
            onChange={e => setFormData({...formData, contact: e.target.value})}
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <label className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Date</label>
            <div className="relative">
              <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input 
                type="date" 
                className="w-full bg-black/30 border border-white/5 rounded-xl h-14 pl-12 pr-4 focus:ring-2 focus:ring-[#00C853] outline-none transition-all"
                value={formData.date}
                onChange={e => setFormData({...formData, date: e.target.value})}
              />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Time</label>
            <div className="relative">
              <Clock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input 
                type="time" 
                className="w-full bg-black/30 border border-white/5 rounded-xl h-14 pl-12 pr-4 focus:ring-2 focus:ring-[#00C853] outline-none transition-all"
                value={formData.time}
                onChange={e => setFormData({...formData, time: e.target.value})}
              />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <label className="text-[10px] text-gray-500 uppercase tracking-[0.2em] font-bold">Guests</label>
