/**
 * A simple fuzzy matching function that checks if characters 
 * of the query exist in the target string in the correct order.
 */
const fuzzyMatch = (query: string, target: string): boolean => {
  const q = query.toLowerCase().replace(/\s/g, '');
  const t = target.toLowerCase();

  // Exact match or includes is always a win
  if (t.includes(q)) return true;

  let queryIdx = 0;
  let targetIdx = 0;

  while (queryIdx < q.length && targetIdx < t.length) {
    if (q[queryIdx] === t[targetIdx]) {
      queryIdx++;
    }
    targetIdx++;
  }

  return queryIdx === q.length;
};

