/**
 * 3D Tilt Component for high-end interaction
 */
const TiltCard: React.FC<{ children: React.ReactNode; onClick?: () => void }> = ({ children, onClick }) => {
  const cardRef = useRef<HTMLDivElement>(null);
  const [rotate, setRotate] = useState({ x: 0, y: 0 });
  const [isHovering, setIsHovering] = useState(false);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement> | React.TouchEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;

    const rect = cardRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const x = clientX - rect.left;
    const y = clientY - rect.top;

    const centerX = rect.width / 2;
    const centerY = rect.height / 2;

    const rotateX = ((y - centerY) / centerY) * -15; 
    const rotateY = ((x - centerX) / centerX) * 15;

    setRotate({ x: rotateX, y: rotateY });
  };

  const onMouseEnter = () => setIsHovering(true);
  const onMouseLeave = () => {
    setIsHovering(false);
    setRotate({ x: 0, y: 0 });
  };

  return (
    <div 
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onTouchMove={handleMouseMove}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      onTouchStart={onMouseEnter}
      onTouchEnd={onMouseLeave}
      onClick={onClick}
      className="relative transition-transform duration-300 ease-out cursor-pointer"
      style={{
        perspective: '1000px',
        transformStyle: 'preserve-3d',
      }}
    >
      <div 
        className="w-full h-full transition-all duration-200 ease-out"
        style={{
          transform: `rotateX(${rotate.x}deg) rotateY(${rotate.y}deg) scale(${isHovering ? 1.02 : 1})`,
          transformStyle: 'preserve-3d',
        }}
      >
        {children}
        {/* Shine/Glare Effect */}
        {isHovering && (
          <div 
            className="absolute inset-0 pointer-events-none rounded-3xl"
            style={{
              background: `radial-gradient(circle at ${rotate.y * 5 + 50}% ${rotate.x * -5 + 50}%, rgba(255,255,255,0.08) 0%, transparent 70%)`,
              zIndex: 10
            }}
          />
        )}
      </div>
    </div>
  );
};

const fuzzyMatch = (query: string, target: string): boolean => {
  const q = query.toLowerCase().replace(/\s/g, '');
  const t = target.toLowerCase();
  if (t.includes(q)) return true;
  let queryIdx = 0;
  let targetIdx = 0;
  while (queryIdx < q.length && targetIdx < t.length) {
    if (q[queryIdx] === t[targetIdx]) queryIdx++;
    targetIdx++;
  }
  return queryIdx === q.length;
};

