            </div>
            <div>
              <h2 className="text-2xl font-black italic tracking-tighter leading-none">{item.name}</h2>
              <p className="text-[#00C853] font-black text-xl">₹{item.price}</p>
            </div>
          </div>
          <button onClick={handleClose} className="p-2 bg-white/5 rounded-full text-gray-400">
            <X size={24} />
          </button>
        </div>

        <div className="bg-black/40 p-1 rounded-2xl flex mb-8 border border-white/5">
          <button 
            onClick={() => changeOrderType('asap')}
            className={`flex-1 h-12 rounded-xl flex items-center justify-center gap-2 font-bold transition-all ${orderType === 'asap' ? 'bg-[#00C853] text-black shadow-lg shadow-[#00C853]/20' : 'text-gray-500'}`}
          >
            <Zap size={18} /> ASAP
          </button>
          <button 
            onClick={() => changeOrderType('schedule')}
            className={`flex-1 h-12 rounded-xl flex items-center justify-center gap-2 font-bold transition-all ${orderType === 'schedule' ? 'bg-[#00C853] text-black shadow-lg shadow-[#00C853]/20' : 'text-gray-500'}`}
          >
            <Clock size={18} /> Schedule
          </button>
        </div>

        <div className="space-y-6">
          {orderType === 'schedule' && (
            <div className="space-y-4 animate-fade-in">
              <div className="space-y-2">
                <label className="text-[10px] text-gray-500 uppercase tracking-widest font-bold ml-2">Select Date</label>
                <div className="relative">
                  <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                  <input 
                    type="date" 
                    value={date}
                    onChange={e => setDate(e.target.value)}
                    className="w-full bg-white/5 border border-white/10 rounded-2xl h-14 pl-12 pr-4 focus:ring-2 focus:ring-[#00C853] outline-none transition-all"
                  />
                </div>
              </div>

              <div className="space-y-2">
