import React, { useState, useEffect } from 'react';

const Loader: React.FC = () => {
  const [progress, setProgress] = useState(0);
  const [isFinished, setIsFinished] = useState(false);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setTimeout(() => setIsFinished(true), 800);
          return 100;
        }
        // Organic progress feel
        const step = Math.random() > 0.8 ? 5 : 1.5;
        return Math.min(100, prev + step);
      });
    }, 40);
    return () => clearInterval(interval);
  }, []);

  return (
    <div 
      className={`fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#0A0A0A] transition-all duration-[1200ms] cubic-bezier(0.85, 0, 0.15, 1) ${
