            className="absolute inset-0 border border-white/5 rounded-full" 
            style={{ transform: `scale(${1 + progress / 200})`, opacity: 0.3 }}
          />

          {/* Progress Circular Stroke */}
          <svg className="absolute inset-0 w-full h-full -rotate-90">
            <circle
