        <div className="h-16 overflow-hidden flex flex-col items-center">
          <div className={`transition-all duration-700 cubic-bezier(0.16, 1, 0.3, 1) ${progress > 20 ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0'}`}>
