import React, { useState, useEffect } from 'react';

const Loader: React.FC = () => {
  const [progress, setProgress] = useState(0);
  const [isFinished, setIsFinished] = useState(false);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setTimeout(() => setIsFinished(true), 1200);
          return 100;
        }
        // Sophisticated progress curve
        const remaining = 100 - prev;
        const step = Math.max(0.2, Math.random() * (remaining / 10));
        return Math.min(100, prev + step);
      });
    }, 50);
    return () => clearInterval(interval);
  }, []);

  return (
    <div 
      className={`fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#0A0A0A] transition-all duration-[1500ms] cubic-bezier(0.85, 0, 0.15, 1) ${
