import React, { useState, useEffect } from 'react';
import { X, Clock, Calendar, User, Phone, ShoppingBag, ChevronRight, Zap, CheckCircle2 } from 'lucide-react';
import { MenuItem } from '../types';
import { CONTACT_NUMBER } from '../constants';
import { playSFX, SFX_URLS } from '../utils/sfx';

interface OrderDrawerProps {
  item: MenuItem | null;
  onClose: () => void;
}

const OrderDrawer: React.FC<OrderDrawerProps> = ({ item, onClose }) => {
  const [orderType, setOrderType] = useState<'asap' | 'schedule'>('asap');
  const [name, setName] = useState(localStorage.getItem('user_name') || '');
  const [phone, setPhone] = useState(localStorage.getItem('user_phone') || '');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  const [selHour, setSelHour] = useState('07');
  const [selMinute, setSelMinute] = useState('00');
  const [selPeriod, setSelPeriod] = useState('PM');

  const hours = Array.from({ length: 12 }, (_, i) => (i + 1).toString().padStart(2, '0'));
  const minutes = Array.from({ length: 12 }, (_, i) => (i * 5).toString().padStart(2, '0'));

  useEffect(() => {
    if (item) {
      playSFX(SFX_URLS.WHOOSH, 0.4);
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => { document.body.style.overflow = 'unset'; };
  }, [item]);

  if (!item) return null;

  const handleClose = () => {
    playSFX(SFX_URLS.WHOOSH, 0.2);
    onClose();
  };

  const handleConfirm = () => {
    playSFX(SFX_URLS.CHIME, 0.5);
    localStorage.setItem('user_name', name);
    localStorage.setItem('user_phone', phone);

    const timing = orderType === 'asap' 
      ? 'ASAP (Immediate Preparation)' 
      : `Scheduled: ${date} at ${selHour}:${selMinute} ${selPeriod}`;

    const message = `*ZERO DEGREES KOTA — NEW CURATION ORDER*%0A%0A` +
      `*Item:* ${item.name.toUpperCase()}%0A` +
      `*Price:* ₹${item.price}%0A` +
      `*Priority:* ${timing}%0A%0A` +
      `*Client Identity*%0A` +
      `*Name:* ${name}%0A` +
      `*Phone:* ${phone}%0A%0A` +
      `Please acknowledge and provide estimated completion.`;

    window.open(`https://wa.me/${CONTACT_NUMBER}?text=${message}`, '_blank');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-end justify-center">
      <div 
        className="absolute inset-0 bg-black/90 backdrop-blur-xl transition-opacity animate-fade-in" 
        onClick={handleClose} 
      />

      <div className="relative w-full max-w-2xl bg-[#0A0A0A] rounded-t-[4rem] p-10 pb-16 shadow-3xl animate-slide-up border-t border-white/10 max-h-[96vh] overflow-y-auto no-scrollbar">
        <div className="w-16 h-1.5 bg-white/10 rounded-full mx-auto mb-12" />

        <div className="flex items-start justify-between mb-12">
          <div className="flex items-center gap-6">
            <div className="w-24 h-24 rounded-[2rem] overflow-hidden border border-white/10 shadow-2xl">
              <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
            </div>
            <div className="space-y-1">
              <h2 className="text-3xl font-black italic tracking-tighter leading-none uppercase">{item.name}</h2>
              <div className="flex items-center gap-2">
                <span className="text-[#00C853] font-black text-2xl">₹{item.price}</span>
                <span className="text-[8px] text-gray-600 font-bold uppercase tracking-widest border border-white/5 px-2 py-0.5 rounded-full">Inc. Taxes</span>
              </div>
            </div>
          </div>
          <button onClick={handleClose} className="p-4 bg-white/5 rounded-full text-gray-500 hover:text-white transition-all">
            <X size={28} />
          </button>
        </div>

        {/* Priority Switcher */}
        <div className="bg-white/5 p-2 rounded-[2.5rem] flex mb-12 border border-white/5 relative">
          <button 
            onClick={() => { playSFX(SFX_URLS.CLICK); setOrderType('asap'); }}
            className={`flex-1 h-16 rounded-[2rem] flex items-center justify-center gap-3 font-black text-xs uppercase tracking-widest transition-all z-10 ${orderType === 'asap' ? 'bg-[#00C853] text-black shadow-2xl' : 'text-gray-500'}`}
          >
            <Zap size={18} fill={orderType === 'asap' ? 'currentColor' : 'none'} /> ASAP Prep
          </button>
          <button 
            onClick={() => { playSFX(SFX_URLS.CLICK); setOrderType('schedule'); }}
            className={`flex-1 h-16 rounded-[2rem] flex items-center justify-center gap-3 font-black text-xs uppercase tracking-widest transition-all z-10 ${orderType === 'schedule' ? 'bg-[#00C853] text-black shadow-2xl' : 'text-gray-500'}`}
          >
            <Clock size={18} fill={orderType === 'schedule' ? 'currentColor' : 'none'} /> Pre-Order
          </button>
        </div>

        <div className="space-y-10">
          {orderType === 'schedule' && (
            <div className="space-y-6 animate-fade-in-up">
              <div className="space-y-3">
                <label className="text-[10px] text-gray-600 uppercase tracking-[0.3em] font-black ml-4">Curation Date</label>
                <div className="relative">
                  <Calendar className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-600" size={20} />
                  <input 
                    type="date" 
                    value={date}
                    onChange={e => setDate(e.target.value)}
                    className="w-full bg-white/5 border border-white/10 rounded-[2rem] h-18 pl-16 pr-6 focus:ring-2 focus:ring-[#00C853]/50 outline-none transition-all font-bold text-white"
                  />
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-[10px] text-gray-600 uppercase tracking-[0.3em] font-black ml-4">Pick-up Window (12H)</label>
                <div className="flex gap-4">
                  {[ 
                    { val: selHour, set: setSelHour, items: hours },
                    { val: selMinute, set: setSelMinute, items: minutes },
                    { val: selPeriod, set: setSelPeriod, items: ['AM', 'PM'] }
                  ].map((group, idx) => (
                    <div key={idx} className="flex-1 bg-white/5 border border-white/10 rounded-2xl h-18 relative px-4 flex items-center">
                      <select 
                        value={group.val} 
                        onChange={(e) => { playSFX(SFX_URLS.CLICK, 0.1); group.set(e.target.value); }}
                        className="w-full bg-transparent outline-none font-black text-center appearance-none text-white text-lg"
                      >
                        {group.items.map(i => <option key={i} value={i} className="bg-[#0A0A0A]">{i}</option>)}
                      </select>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          <div className="space-y-8">
            <div className="space-y-3">
              <label className="text-[10px] text-gray-600 uppercase tracking-[0.3em] font-black ml-4">Your Identity</label>
              <div className="relative">
                <User className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-600" size={20} />
                <input 
                  type="text" 
                  placeholder="Ex: Alexander Singh"
                  value={name}
                  onChange={e => setName(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-[2rem] h-18 pl-16 pr-6 focus:ring-2 focus:ring-[#00C853]/50 outline-none transition-all font-bold text-white"
                />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-[10px] text-gray-600 uppercase tracking-[0.3em] font-black ml-4">Contact Secure</label>
              <div className="relative">
                <Phone className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-600" size={20} />
                <input 
                  type="tel" 
                  placeholder="+91 00000 00000"
                  value={phone}
                  onChange={e => setPhone(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-[2rem] h-18 pl-16 pr-6 focus:ring-2 focus:ring-[#00C853]/50 outline-none transition-all font-bold text-white"
                />
              </div>
            </div>
          </div>
        </div>

        <div className="mt-16 space-y-6">
          <button 
            onClick={handleConfirm}
            disabled={!name || !phone}
            className="w-full h-22 bg-[#00C853] text-black rounded-[2.5rem] font-black text-xl flex items-center justify-center gap-4 active:scale-95 transition-all shadow-[0_25px_60px_rgba(0,200,83,0.4)] disabled:opacity-20 disabled:grayscale disabled:cursor-not-allowed group"
          >
            {orderType === 'asap' ? 'TRANSMIT ORDER NOW' : 'SECURE PRE-ORDER'}
            <div className="bg-black/10 p-2 rounded-full group-hover:bg-black/20 transition-colors">
              <ChevronRight size={28} strokeWidth={3} />
            </div>
          </button>

          <div className="flex items-center justify-center gap-4 text-gray-700">
             <div className="flex items-center gap-2">
                <CheckCircle2 size={12} className="text-[#00C853]" />
                <span className="text-[8px] font-black uppercase tracking-[0.2em]">Encrypted</span>
             </div>
             <div className="flex items-center gap-2">
                <CheckCircle2 size={12} className="text-[#00C853]" />
                <span className="text-[8px] font-black uppercase tracking-[0.2em]">WhatsApp Direct</span>
             </div>
          </div>
        </div>

        <p className="text-center text-gray-800 text-[8px] mt-10 uppercase tracking-[0.5em] font-black border-t border-white/5 pt-10">
          Zero Degrees Kota — Secure Architecture Order
        </p>
      </div>

      <style>{`
        @keyframes slide-up { from { transform: translateY(100%); } to { transform: translateY(0); } }
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes fade-in-up { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
        .animate-slide-up { animation: slide-up 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-fade-in { animation: fade-in 0.4s ease-out; }
        .animate-fade-in-up { animation: fade-in-up 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .h-22 { height: 5.5rem; }
      `}</style>
    </div>
  );
};

export default OrderDrawer;

import React, { useState, useRef, useEffect } from 'react';
import { Search, Plus, ShoppingBag, X, ChefHat, Timer, Flame, Filter, ChevronRight, Sparkles } from 'lucide-react';
import { MENU_ITEMS } from '../constants';
import { MenuItem } from '../types';
import OrderDrawer from '../components/OrderDrawer';
import { playSFX, SFX_URLS } from '../utils/sfx';

const MenuPage: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
