              type="text"
              placeholder="Search by flavor profile..."
              className="w-full bg-white/5 border border-white/10 rounded-2xl h-16 pl-14 pr-6 focus:ring-2 focus:ring-[#00C853]/50 outline-none transition-all placeholder:text-gray-700 font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex gap-3 overflow-x-auto no-scrollbar py-2">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => handleCategoryChange(cat)}
                className={`px-8 py-4 rounded-2xl whitespace-nowrap text-xs font-black uppercase tracking-widest transition-all duration-300 border ${
                  selectedCategory === cat 
                  ? 'bg-[#00C853] text-black border-[#00C853] shadow-[0_15px_30px_rgba(0,200,83,0.3)] translate-y-[-2px]' 
                  : 'bg-white/5 border-white/5 text-gray-500 hover:border-white/10'
