          filteredItems.map((item, idx) => (
            <div 
              key={item.id} 
              onClick={() => { playSFX(SFX_URLS.WHOOSH, 0.2); setSelectedItem(item); }}
              className="group bg-[#121212] rounded-[3rem] border border-white/5 p-6 flex flex-col md:flex-row gap-8 transition-all duration-500 hover:border-[#00C853]/30 hover:shadow-2xl animate-fade-in-up"
              style={{ animationDelay: `${idx * 100}ms` }}
            >
