const RankingPage: React.FC = () => {
  // Use the current date to seed a "daily" random selection
  const dailyTopCustomers = useMemo(() => {
    const today = new Date();
    // Simple date-based seed string
    const seedString = `${today.getFullYear()}-${today.getMonth()}-${today.getDate()}`;

    // Simple hash function to get a deterministic "random" number for the day
    const getHash = (str: string) => {
      let hash = 0;
      for (let i = 0; i < str.length; i++) {
        const char = str.charCodeAt(i);
        hash = (hash << 5) - hash + char;
        hash = hash & hash; // Convert to 32bit integer
      }
      return Math.abs(hash);
    };

    const hash = getHash(seedString);

    // Create a copy of the potential customers to shuffle
    const shuffled = [...POTENTIAL_CUSTOMERS];

    // Deterministic shuffle based on hash
    for (let i = shuffled.length - 1; i > 0; i--) {
      const j = (hash + i) % (i + 1);
      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }

    // Return top 5 with deterministic "random" order counts for variety
    return shuffled.slice(0, 5).map((c, idx) => ({
      ...c,
      // Order counts follow a power-law feel, deterministic based on day + rank
      orders: Math.floor(50 - idx * 7 + (hash % 5))
    }));
  }, []);

  const topThree = dailyTopCustomers.slice(0, 3);

  return (
    <div className="min-h-screen bg-[#0A0A0A] pb-32 animate-fade-in">
