import React, { useState, useEffect, useMemo } from 'react';
import { X, Clock, Calendar, User, Phone, ShoppingBag, ChevronRight, Zap, CheckCircle2 } from 'lucide-react';
import { MenuItem } from '../types';
import { CONTACT_NUMBER } from '../constants';
import { playSFX, SFX_URLS } from '../utils/sfx';

interface OrderDrawerProps {
  item: MenuItem | null;
  onClose: () => void;
  defaultType?: 'asap' | 'schedule';
}

const OrderDrawer: React.FC<OrderDrawerProps> = ({ item, onClose, defaultType = 'asap' }) => {
  const [orderType, setOrderType] = useState<'asap' | 'schedule'>(defaultType);
  const [name, setName] = useState(localStorage.getItem('user_name') || '');
  const [phone, setPhone] = useState(localStorage.getItem('user_phone') || '');

  // Date Selection (Next 7 days)
  const availableDates = useMemo(() => {
    const dates = [];
    for (let i = 0; i < 7; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      dates.push({
        full: d.toISOString().split('T')[0],
        label: i === 0 ? 'Today' : i === 1 ? 'Tomorrow' : d.toLocaleDateString('en-US', { weekday: 'short', day: 'numeric' })
      });
    }
    return dates;
  }, []);

  const [selectedDate, setSelectedDate] = useState(availableDates[0].full);

  // Time Slot Generation (15-min intervals from 11 AM to 11 PM)
  const timeSlots = useMemo(() => {
    const slots = [];
    const startHour = 11;
    const endHour = 23;
    for (let h = startHour; h < endHour; h++) {
      for (let m = 0; m < 60; m += 15) {
        const period = h >= 12 ? 'PM' : 'AM';
        const displayHour = h > 12 ? h - 12 : h === 0 ? 12 : h;
        const displayMinute = m.toString().padStart(2, '0');
        slots.push(`${displayHour}:${displayMinute} ${period}`);
      }
    }
    return slots;
  }, []);

  const [selectedTime, setSelectedTime] = useState(timeSlots[0]);

  useEffect(() => {
    if (item) {
      setOrderType(defaultType);
      playSFX(SFX_URLS.WHOOSH, 0.4);
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => { document.body.style.overflow = 'unset'; };
  }, [item, defaultType]);

  if (!item) return null;

  const handleClose = () => {
    playSFX(SFX_URLS.WHOOSH, 0.2);
    onClose();
  };

  const handleConfirm = () => {
    playSFX(SFX_URLS.CHIME, 0.5);
    localStorage.setItem('user_name', name);
    localStorage.setItem('user_phone', phone);

    const timing = orderType === 'asap' 
      ? 'ASAP (Priority Assembly)' 
      : `SCHEDULED: ${selectedDate} at ${selectedTime}`;

    const message = `*ZERO DEGREES KOTA — PRE-ORDER*%0A%0A` +
      `*Item:* ${item.name.toUpperCase()}%0A` +
      `*Price:* ₹${item.price}%0A` +
      `*Timing:* ${timing}%0A%0A` +
      `*Identity*%0A` +
      `*Name:* ${name}%0A` +
      `*Phone:* ${phone}%0A%0A` +
      `Please reserve this flavor slot for me.`;

    window.open(`https://wa.me/${CONTACT_NUMBER}?text=${message}`, '_blank');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-end justify-center">
      <div className="absolute inset-0 bg-black/90 backdrop-blur-xl animate-fade-in" onClick={handleClose} />

      <div className="relative w-full max-w-2xl bg-[#0A0A0A] rounded-t-[4rem] p-8 pb-12 shadow-3xl animate-slide-up border-t border-white/10 max-h-[96vh] overflow-y-auto no-scrollbar">
        <div className="w-12 h-1 bg-white/10 rounded-full mx-auto mb-8" />

        <div className="flex items-start justify-between mb-8">
          <div className="flex items-center gap-4">
            <img src={item.image} alt={item.name} className="w-20 h-20 rounded-2xl object-cover border border-white/10" />
            <div>
              <h2 className="text-2xl font-black italic tracking-tighter uppercase">{item.name}</h2>
              <span className="text-[#00C853] font-black text-xl">₹{item.price}</span>
            </div>
          </div>
          <button onClick={handleClose} className="p-3 bg-white/5 rounded-full text-gray-500"><X size={24} /></button>
        </div>

        {/* Priority Switcher */}
        <div className="bg-white/5 p-1.5 rounded-2xl flex mb-8 border border-white/5">
          <button 
            onClick={() => { playSFX(SFX_URLS.CLICK); setOrderType('asap'); }}
            className={`flex-1 h-12 rounded-xl flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest transition-all ${orderType === 'asap' ? 'bg-[#00C853] text-black shadow-lg' : 'text-gray-500'}`}
          >
            <Zap size={14} fill={orderType === 'asap' ? 'currentColor' : 'none'} /> ASAP
          </button>
          <button 
            onClick={() => { playSFX(SFX_URLS.CLICK); setOrderType('schedule'); }}
            className={`flex-1 h-12 rounded-xl flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest transition-all ${orderType === 'schedule' ? 'bg-[#00C853] text-black shadow-lg' : 'text-gray-500'}`}
          >
            <Clock size={14} fill={orderType === 'schedule' ? 'currentColor' : 'none'} /> Pre-Order
          </button>
        </div>

        <div className="space-y-8">
          {orderType === 'schedule' && (
            <div className="space-y-6 animate-fade-in-up">
              {/* DATE PICKER */}
              <div className="space-y-3">
                <label className="text-[9px] text-gray-600 uppercase tracking-widest font-black ml-2">Select Date</label>
                <div className="flex gap-2 overflow-x-auto no-scrollbar pb-2">
                  {availableDates.map(date => (
                    <button
                      key={date.full}
                      onClick={() => { playSFX(SFX_URLS.CLICK, 0.1); setSelectedDate(date.full); }}
                      className={`px-6 py-3 rounded-xl whitespace-nowrap text-[10px] font-black uppercase border transition-all ${selectedDate === date.full ? 'bg-white text-black border-white' : 'bg-white/5 border-white/5 text-gray-500'}`}
                    >
                      {date.label}
                    </button>
                  ))}
                </div>
              </div>

              {/* TIME SLOT PICKER */}
              <div className="space-y-3">
                <label className="text-[9px] text-gray-600 uppercase tracking-widest font-black ml-2">Select Time Slot</label>
                <div className="grid grid-cols-3 gap-2">
                  {timeSlots.map(slot => (
                    <button
                      key={slot}
                      onClick={() => { playSFX(SFX_URLS.CLICK, 0.1); setSelectedTime(slot); }}
                      className={`py-3 rounded-xl text-[10px] font-black border transition-all ${selectedTime === slot ? 'bg-[#00C853] text-black border-[#00C853]' : 'bg-white/5 border-white/5 text-gray-400'}`}
                    >
                      {slot}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}

          <div className="space-y-6">
            <div className="space-y-3">
              <label className="text-[9px] text-gray-600 uppercase tracking-widest font-black ml-2">Your Name</label>
              <div className="relative">
                <User className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-600" size={18} />
                <input 
                  type="text" 
                  value={name}
                  onChange={e => setName(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl h-14 pl-14 pr-6 focus:ring-2 focus:ring-[#00C853]/50 outline-none transition-all font-bold text-white"
                  placeholder="Alexander Singh"
                />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-[9px] text-gray-600 uppercase tracking-widest font-black ml-2">Contact Secure</label>
              <div className="relative">
                <Phone className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-600" size={18} />
                <input 
                  type="tel" 
                  value={phone}
                  onChange={e => setPhone(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl h-14 pl-14 pr-6 focus:ring-2 focus:ring-[#00C853]/50 outline-none transition-all font-bold text-white"
                  placeholder="+91 00000 00000"
                />
              </div>
            </div>
          </div>
        </div>

        <button 
          onClick={handleConfirm}
          disabled={!name || !phone}
          className="w-full h-20 bg-[#00C853] text-black rounded-[2rem] font-black text-lg flex items-center justify-center gap-4 mt-12 shadow-[0_20px_40px_rgba(0,200,83,0.3)] disabled:opacity-20 active:scale-95 transition-all"
        >
          {orderType === 'asap' ? 'TRANSMIT ORDER' : 'RESERVE SLOT'}
          <ChevronRight size={24} strokeWidth={3} />
        </button>
      </div>

      <style>{`
