import React, { useState, useEffect, useRef } from 'react';

const Loader: React.FC = () => {
  const [progress, setProgress] = useState(0);
  const [isFinished, setIsFinished] = useState(false);
  const [statusIdx, setStatusIdx] = useState(0);

  const statusMessages = [
    "INITIALIZING_CRYOGENICS",
    "CALIBRATING_FLAVOR_GEOMETRY",
    "STRUCTURING_VEG_CORE",
    "OPTIMIZING_KOTA_VIBES",
    "REACHING_ABSOLUTE_ZERO"
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setTimeout(() => setIsFinished(true), 1500);
          return 100;
        }
        const remaining = 100 - prev;
        const step = Math.max(0.1, Math.random() * (remaining / 8));
        return Math.min(100, prev + step);
      });
    }, 40);

    const statusInterval = setInterval(() => {
      setStatusIdx(prev => (prev + 1) % statusMessages.length);
    }, 600);

    return () => {
      clearInterval(interval);
      clearInterval(statusInterval);
    };
  }, []);

  // Generate random particles for the "frost" effect
  const particles = Array.from({ length: 20 }).map((_, i) => ({
    id: i,
    left: `${Math.random() * 100}%`,
    top: `${Math.random() * 100}%`,
    duration: `${2 + Math.random() * 4}s`,
    delay: `${Math.random() * 2}s`,
    size: `${Math.random() * 3 + 1}px`
  }));

  return (
    <div 
      className={`fixed inset-0 z-[250] flex flex-col items-center justify-center bg-[#050505] transition-all duration-[1200ms] cubic-bezier(0.9, 0, 0.1, 1) ${
        isFinished ? 'opacity-0 scale-110 pointer-events-none' : 'opacity-100 scale-100'
      }`}
    >
      {/* Cinematic Background Particles */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        {particles.map(p => (
          <div 
            key={p.id}
            className="absolute rounded-full bg-[#00C853]/20 blur-[1px] animate-frost-float"
            style={{ 
              left: p.left, 
              top: p.top, 
              width: p.size, 
              height: p.size, 
              animationDuration: p.duration,
              animationDelay: p.delay
            }}
          />
        ))}

        {/* Holographic Scanline */}
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-[#00C853]/5 to-transparent h-[10vh] w-full animate-scanline pointer-events-none" />

        {/* Deep Glow Radial */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[100vw] h-[100vw] bg-[#00C853]/5 blur-[200px] rounded-full animate-pulse-slow opacity-30" />
      </div>

      <div className="relative flex flex-col items-center justify-center w-full max-w-lg z-10">

        {/* The Kinetic Large "0" */}
        <div className="relative mb-16">
          <div className="text-[18rem] md:text-[24rem] font-black italic tracking-tighter text-white/[0.02] leading-none select-none">
            0
          </div>

          {/* Progress Filled "0" with Liquid Wave */}
          <div className="absolute inset-0 overflow-hidden" style={{ clipPath: `inset(${100 - progress}% 0 0 0)` }}>
            <div className="text-[18rem] md:text-[24rem] font-black italic tracking-tighter text-white leading-none select-none relative">
              0
              {/* Internal Glow for filled part */}
              <div className="absolute inset-0 bg-[#00C853]/10 blur-xl opacity-50" />
            </div>
          </div>

          {/* Liquid Ripple Line */}
          <div 
            className="absolute left-0 right-0 h-1 bg-white shadow-[0_0_15px_#fff] transition-all duration-300 z-20"
            style={{ bottom: `${progress}%`, opacity: progress > 0 && progress < 100 ? 1 : 0 }}
          />

          {/* Degree Symbol Reveal */}
          <div 
            className="absolute top-1/4 -right-12 text-8xl md:text-9xl font-black text-[#00C853] transition-all duration-1000 cubic-bezier(0.16, 1, 0.3, 1)"
            style={{ 
              opacity: progress > 70 ? 1 : 0, 
              transform: `translate(${progress > 70 ? '0' : '50px'}, ${progress > 70 ? '0' : '-20px'}) rotate(${progress > 70 ? '0deg' : '45deg'})`,
              filter: 'drop-shadow(0 0 30px rgba(0,200,83,0.6))'
            }}
          >
            °
          </div>
        </div>

        {/* Branding Typography Glitch Reveal */}
        <div className="flex flex-col items-center gap-2 overflow-hidden">
          <div className={`transition-all duration-1000 ${progress > 20 ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0'}`}>
            <h1 className="text-4xl md:text-5xl font-black italic tracking-[0.25em] text-white uppercase flex items-center gap-4">
              ZERO <span className="text-[#00C853] relative">
                DEGREES
                <span className="absolute -inset-1 bg-[#00C853]/10 blur-lg animate-pulse" />
              </span>
            </h1>
          </div>
          <div className={`h-[1px] bg-white/10 transition-all duration-1000 ${progress > 40 ? 'w-48' : 'w-0'}`} />
          <div className={`transition-all duration-1000 delay-300 ${progress > 50 ? 'translate-y-0 opacity-40' : 'translate-y-full opacity-0'}`}>
            <span className="text-[10px] font-black tracking-[0.8em] text-gray-400 uppercase">ARCHITECTURAL TASTE</span>
          </div>
        </div>

        {/* Status Hub */}
        <div className="absolute bottom-[-180px] w-full flex flex-col items-center gap-6">
          {/* Progress Bar Container */}
          <div className="w-64 space-y-3">
             <div className="flex justify-between items-end px-1">
                <span className="font-mono text-[8px] text-[#00C853] uppercase tracking-[0.2em] animate-pulse">
                  {statusMessages[statusIdx]}
                </span>
                <span className="font-mono text-[10px] text-white font-bold">
                  {Math.round(progress)}%
                </span>
             </div>
             <div className="h-[2px] w-full bg-white/5 relative overflow-hidden rounded-full">
                <div 
                  className="absolute inset-y-0 left-0 bg-[#00C853] shadow-[0_0_15px_rgba(0,200,83,0.8)] transition-all duration-300 ease-out"
                  style={{ width: `${progress}%` }}
                />
             </div>
          </div>

          <div className="flex gap-1">
            {[1,2,3].map(i => (
              <div key={i} className={`w-1 h-1 rounded-full transition-all duration-500 ${progress > (i * 25) ? 'bg-[#00C853] scale-110' : 'bg-white/10'}`} />
            ))}
          </div>
        </div>
      </div>

      {/* Finishing Flash */}
      <div className={`fixed inset-0 bg-white z-[300] transition-opacity duration-700 pointer-events-none ${progress === 100 && !isFinished ? 'opacity-20' : 'opacity-0'}`} />

      <style>{`
        @keyframes frost-float {
          0%, 100% { transform: translate(0, 0) scale(1); opacity: 0.2; }
          50% { transform: translate(10px, -20px) scale(1.5); opacity: 0.4; }
        }
        @keyframes scanline {
          0% { transform: translateY(-100%); }
          100% { transform: translateY(1000%); }
        }
        @keyframes pulse-slow {
          0%, 100% { opacity: 0.3; transform: translate(-50%, -50%) scale(1); }
