  const offset = circumference - (progress / 100) * circumference;

  return (
    <div 
      className={`fixed inset-0 z-[250] flex flex-col items-center justify-center bg-[#080808] transition-all duration-[1000ms] cubic-bezier(0.9, 0, 0.1, 1) ${
